import{_ as t,o,c as r,ae as a}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Configure SSO With Azure","description":"","frontmatter":{"title":"Configure SSO With Azure","slug":"configure-sso-with-azure"},"headers":[],"relativePath":"account-hub/configure-sso-with-azure.md","filePath":"account-hub/configure-sso-with-azure.md"}'),n={name:"account-hub/configure-sso-with-azure.md"};function i(s,e,l,c,u,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>This guide provides step-by-step instructions for setting up Single Sign-On (SSO) with Branch using <strong>Microsoft Entra ID</strong> (formerly Azure Active Directory) as your Identity Provider (IdP).</p><p>This guide will:</p><ol><li>Help you get your configuration details from Branch.</li><li>Show you how to create and configure a SAML 2.0 application in Microsoft Entra ID.</li><li>Link you back to the main <a href="./configure-sso.html">Configure SSO guide</a> to complete the setup.</li></ol><h2 id="configure-sso" tabindex="-1">Configure SSO <a class="header-anchor" href="#configure-sso" aria-label="Permalink to &quot;Configure SSO&quot;">​</a></h2><p>To configure SSO, you’ll need to get your unique URLs from Branch, configure Microsoft Entra ID, and then finish the setup in Branch.</p><h3 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h3><p>Before you begin, ensure you have:</p><ul><li><p>Admin access to your Branch account.</p></li><li><p>Admin access to your Azure portal and the Microsoft Entra ID service.</p></li><li><p>SSO enabled for your Branch account.</p><ul><li>Access to SSO requires a Branch plan. Please visit our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing</a> page or <a href="https://branchdocs.app.link/e/sso-sign-up" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</li></ul></li></ul><h3 id="step-1-get-configuration-details-from-branch" tabindex="-1">Step 1: Get configuration details from Branch <a class="header-anchor" href="#step-1-get-configuration-details-from-branch" aria-label="Permalink to &quot;Step 1: Get configuration details from Branch&quot;">​</a></h3><p>This step is different depending on whether you are on the <a href="./branch-dashboard-overview.html">legacy</a> or <a href="./new-branch-overview.html">new</a> Branch experience. The rest of the steps remain the same between the two platforms.</p><h3 id="step-2-create-a-custom-saml-app-in-azure" tabindex="-1">Step 2: Create a custom SAML app in Azure <a class="header-anchor" href="#step-2-create-a-custom-saml-app-in-azure" aria-label="Permalink to &quot;Step 2: Create a custom SAML app in Azure&quot;">​</a></h3><p>Now, log in to the Azure portal to create the Branch enterprise application.</p><ol><li>In the Azure portal, navigate to <strong>Microsoft Entra ID → Enterprise applications</strong>.</li><li>Select <strong>New application</strong>.</li><li>Select <strong>Create your own application</strong>.</li><li>Enter an application name (e.g., “Branch SSO”) and select the option to <strong>Integrate any other application you don’t find in the gallery (Non-gallery)</strong>.</li><li>Select <strong>Create</strong>.</li></ol><h3 id="step-3-configure-sso-settings-in-azure" tabindex="-1">Step 3: Configure SSO settings in Azure <a class="header-anchor" href="#step-3-configure-sso-settings-in-azure" aria-label="Permalink to &quot;Step 3: Configure SSO settings in Azure&quot;">​</a></h3><p>Within your new enterprise application in Azure, configure the SAML settings.</p><ol><li><p>Navigate to <strong>Single sign-on</strong> in the left menu.</p></li><li><p>On the <strong>Select a single sign-on method</strong> page, select the <strong>SAML</strong> tile.</p></li><li><p>In the <strong>Basic SAML Configuration</strong> section, select <strong>Edit</strong>.</p></li><li><p>Fill in the fields using the values from the Branch tab you kept open from <a href="./configure-sso-with-azure.html#step-1-get-configuration-details-from-branch">step 1</a>:</p><ol><li>Identifier (Entity ID): Paste the <code>Service Provider Entity ID</code> from Branch.</li><li>Reply URL (Assertion Consumer Service URL): Paste the <code>Single Sign-On URL</code> from Branch.</li></ol></li><li><p>Select <strong>Save</strong>.</p></li></ol><h3 id="step-4-map-attributes-in-azure" tabindex="-1">Step 4: Map attributes in Azure <a class="header-anchor" href="#step-4-map-attributes-in-azure" aria-label="Permalink to &quot;Step 4: Map attributes in Azure&quot;">​</a></h3><p>Branch requires three attributes to be sent in the SAML response to provision and identify users.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>To set up a successful mapping, you must use the attribute names <code>firstName</code>, <code>lastName</code>, and <code>email</code> exactly as they are capitalized and spelled here. Do not use URN or OID formats.</p></div><ol><li><p>In the <strong>Attributes &amp; Claims</strong> section, select <strong>Edit</strong>.</p></li><li><p>Delete any default claims that are not required (you can keep the default unique user identifier claim).</p></li><li><p>Add the following three attributes by selecting <strong>Add new claim</strong> for each:</p><table tabindex="0"><thead><tr><th><strong>Claim Name</strong></th><th><strong>Value</strong></th></tr></thead><tbody><tr><td><code>email</code></td><td>user.mail</td></tr><tr><td><code>firstName</code></td><td>user.givenname</td></tr><tr><td><code>lastName</code></td><td>user.surname</td></tr></tbody></table></li><li><p>For each attribute:</p><ol><li>Enter the <strong>Name</strong> exactly as shown above (case-sensitive).</li><li>Set the <strong>Namespace</strong> to blank (leave empty).</li><li>Select <strong>Attribute</strong> as the <strong>Source</strong>.</li><li>Select the corresponding <strong>Source attribute</strong> from the table above.</li></ol></li></ol><h3 id="step-5-get-federation-metadata-from-azure" tabindex="-1">Step 5: Get federation metadata from Azure <a class="header-anchor" href="#step-5-get-federation-metadata-from-azure" aria-label="Permalink to &quot;Step 5: Get federation metadata from Azure&quot;">​</a></h3><p>Branch needs your Microsoft Entra ID federation metadata to complete the connection.</p><ol><li>In the <strong>SAML Certificates</strong> section of your Azure SAML configuration, locate the <strong>App Federation Metadata Url</strong>.</li><li>Copy this URL so you have it ready for the next step.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>Below the <strong>SAML Certificates</strong> section in Azure, you will see a section called <strong>Set up Branch SSO</strong>. This is for manual setup using individual values.</p><p>Using the <strong>App Federal Metadata Url</strong> instead is the automatic and recommended setup.</p></div><h3 id="step-6-complete-connection-in-branch" tabindex="-1">Step 6: Complete connection in Branch <a class="header-anchor" href="#step-6-complete-connection-in-branch" aria-label="Permalink to &quot;Step 6: Complete connection in Branch&quot;">​</a></h3><p>Now you’ll provide Microsoft Entra ID’s metadata to Branch and test the connection.</p><ol><li>Go back to your Branch <strong>Configure Custom SAML</strong> browser tab.</li><li>Complete <a href="./configure-sso.html#step-23-configure-connection">step 2.3 in our main guide</a>. Paste the <strong>App Federation Metadata Url</strong> from Azure into the <strong>Metadata URL</strong> field in Branch.</li><li>Select <strong>Create Connection</strong>.</li></ol><h3 id="step-7-test-sso" tabindex="-1">Step 7: Test SSO <a class="header-anchor" href="#step-7-test-sso" aria-label="Permalink to &quot;Step 7: Test SSO&quot;">​</a></h3><p>Use <a href="./configure-sso.html#step-24-test-sso">step 2.4</a> from our main SSO guide to test the connection between Microsoft Entra ID and Branch.</p><h2 id="more-information" tabindex="-1">More information <a class="header-anchor" href="#more-information" aria-label="Permalink to &quot;More information&quot;">​</a></h2><p>For more complete information about configuring SSO for Branch, visit our <a href="./configure-sso.html">Configure SSO (General SAML) guide</a>.</p>',32)])])}const g=t(n,[["render",i]]);export{d as __pageData,g as default};
